"use client";

import Image, { type StaticImageData } from "next/image";
import { type ReactNode, startTransition, useEffect, useState } from "react";
import { AnimatePresence, LayoutGroup, motion, useReducedMotion } from "framer-motion";
import {
  ArrowUpRight,
  ChevronLeft,
  ChevronRight,
  Mail,
  MessageCircle,
  Twitter,
  X,
  type LucideIcon,
} from "lucide-react";

import {
  AudioParticleField,
  type AudioParticleTheme,
} from "@/components/profile/audio-particle-field";
import {
  PROFILE_SITE_DATA,
  type ContactSection,
  type GalleryFit,
  type GalleryItem,
  type GallerySection,
  type ProfileContentEntry,
  type ProfileContentMap,
  type SocialIconKey,
  type SocialLink,
} from "@/components/profile/profile-site-data";
import { cn } from "@/lib/utils";

const PRELOADED_ASSETS = new Map<string, Promise<void>>();

const SITE_DATA = {
  personal: {
    ...PROFILE_SITE_DATA.personal,
    theme: {
      background: "from-[#1b110d] via-[#140d0a] to-[#080607]",
      backgroundImageOpacity: "opacity-[0.12]",
      orbPrimary: "bg-[#f9c58c]/20",
      orbSecondary: "bg-[#ff8f5c]/18",
      accentText: "text-[#ffe2c5]",
      accentSurface: "bg-[#f7c89b]",
      accentBorder: "border-[#f7c89b]/40",
      badge: "bg-[#f7c89b]/12 text-[#ffe6ce]",
      glow: "shadow-[0_0_90px_rgba(255,216,184,0.28)]",
      particleColor: "#f7e8cb",
      particleGlow: "#f3b672",
      particleDensity: 0.50, //0.82
      particleSpeed: 0.20,
      particleAmplitude: 0.26,
    },
  },
  group: {
    ...PROFILE_SITE_DATA.group,
    theme: {
      background: "from-[#030816] via-[#02050e] to-[#000104]",
      backgroundImageOpacity: "opacity-[0.05]",
      orbPrimary: "bg-[#6a8cff]/16",
      orbSecondary: "bg-[#dbe5ff]/12",
      accentText: "text-[#dce6ff]",
      accentSurface: "bg-[#dce6ff]",
      accentBorder: "border-[#9fb7ff]/35",
      badge: "bg-white/8 text-[#eff4ff]",
      glow: "shadow-[0_0_110px_rgba(112,150,255,0.24)]",
      particleColor: "#eef4ff",
      particleGlow: "#7da1ff",
      particleDensity: 0.32,
      particleSpeed: 0.45,
      particleAmplitude: 0.52,
    },
  },
} satisfies SiteDataMap;

const SOCIAL_ICONS = {
  twitter: Twitter,
  discord: MessageCircle,
  mail: Mail,
} satisfies Record<SocialIconKey, LucideIcon>;

const GALLERY_TABS = ["works", "commission"] as const;
const TAB_ORDER = ["works", "commission", "contact"] as const;
const PERSONAL_TABS = ["works", "commission", "contact"] as const;
const GROUP_TABS = ["works", "contact"] as const;
const INITIAL_SLIDE_STATE: SlideState = {
  personal: { works: 0, commission: 0 },
  group: { works: 0, commission: 0 },
};
const QUICK_EASE: BezierEase = [0.25, 0.1, 0.25, 1];
const LUXE_EASE: BezierEase = [0.22, 1, 0.36, 1];

export function ProfilePage() {
  const [identity, setIdentity] = useState<IdentityKey>("personal");
  const [activeTab, setActiveTab] = useState<TabKey>("works");
  const [slideState, setSlideState] = useState<SlideState>(INITIAL_SLIDE_STATE);
  const [lightboxOpen, setLightboxOpen] = useState(false);
  const [pendingIdentity, setPendingIdentity] = useState<IdentityKey | null>(null);
  const [preloadedIdentities, setPreloadedIdentities] = useState<Record<IdentityKey, boolean>>({
    personal: false,
    group: false,
  });

  const reduceMotion = Boolean(useReducedMotion());
  const profile = SITE_DATA[identity];
  const currentGalleryIndex =
    activeTab === "contact" ? 0 : slideState[identity][activeTab];
  const currentSection =
    activeTab === "contact" ? null : profile.sections[activeTab];
  const currentItem = currentSection?.items[currentGalleryIndex] ?? null;

  useEffect(() => {
    const hash = window.location.hash.replace("#", "") as IdentityKey;
    if (hash === "personal" || hash === "group") {
      setIdentity(hash);
    }
  }, []);

  useEffect(() => {
    let cancelled = false;

    (Object.entries(SITE_DATA) as [IdentityKey, ProfileEntry][]).forEach(
      ([key, entry]) => {
        preloadProfileAssets(entry).then(() => {
          if (cancelled) {
            return;
          }

          setPreloadedIdentities((previous) =>
            previous[key] ? previous : { ...previous, [key]: true },
          );
        });
      },
    );

    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    if (!lightboxOpen) {
      return;
    }

    const previousOverflow = document.body.style.overflow;
    document.body.style.overflow = "hidden";

    return () => {
      document.body.style.overflow = previousOverflow;
    };
  }, [lightboxOpen]);

  useEffect(() => {
    if (!pendingIdentity || !preloadedIdentities[pendingIdentity]) {
      return;
    }

    startTransition(() => {
      setIdentity(pendingIdentity);
      setPendingIdentity(null);
      setLightboxOpen(false);
    });
  }, [pendingIdentity, preloadedIdentities]);

  useEffect(() => {
    if (!lightboxOpen || activeTab === "contact" || !currentSection) {
      return;
    }

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        setLightboxOpen(false);
      }

      if (event.key === "ArrowRight") {
        updateSlide(activeTab, 1);
      }

      if (event.key === "ArrowLeft") {
        updateSlide(activeTab, -1);
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [activeTab, currentSection, identity, lightboxOpen]);

  const updateSlide = (tab: GalleryTab, step: -1 | 1) => {
    const items = SITE_DATA[identity].sections[tab].items;
    if (items.length <= 1) {
      return;
    }

    setSlideState((previous) => ({
      ...previous,
      [identity]: {
        ...previous[identity],
        [tab]: wrapIndex(previous[identity][tab] + step, items.length),
      },
    }));
  };

  const jumpToSlide = (tab: GalleryTab, index: number) => {
    setSlideState((previous) => ({
      ...previous,
      [identity]: {
        ...previous[identity],
        [tab]: index,
      },
    }));
  };

  const handleIdentityChange = (nextIdentity: IdentityKey) => {
    if (nextIdentity === identity) {
      setPendingIdentity(null);
      return;
    }

    if (nextIdentity === pendingIdentity) {
      return;
    }

    window.history.replaceState(null, "", `#${nextIdentity}`);

    if (preloadedIdentities[nextIdentity]) {
      startTransition(() => {
        setIdentity(nextIdentity);
        setPendingIdentity(null);
        setLightboxOpen(false);
      });
      return;
    }

    setPendingIdentity(nextIdentity);
  };

  const handleTabChange = (tab: TabKey) => {
    if (tab === activeTab) {
      return;
    }

    startTransition(() => {
      setActiveTab(tab);
      setLightboxOpen(false);
    });
  };

  const sectionTransition: MotionTransition = {
    duration: reduceMotion ? 0.18 : 0.55,
    ease: reduceMotion ? QUICK_EASE : LUXE_EASE,
  };

  const imageTransition: MotionTransition = {
    duration: reduceMotion ? 0.18 : 0.45,
    ease: reduceMotion ? QUICK_EASE : LUXE_EASE,
  };

  return (
    <div className="relative isolate min-h-screen overflow-hidden bg-[#080607] text-white">
      <div
        className={cn(
          "pointer-events-none absolute inset-0 bg-cover bg-center mix-blend-screen",
          profile.theme.backgroundImageOpacity,
        )}
        style={{ backgroundImage: "url('/images/profile-bg.jpg')" }}
      />
      <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(circle_at_top,rgba(255,255,255,0.08),transparent_55%)]" />

      <AnimatePresence mode="wait">
        <motion.div
          key={`${identity}-background`}
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          transition={sectionTransition}
          className={cn(
            "pointer-events-none absolute inset-0 bg-gradient-to-b",
            profile.theme.background,
          )}
        >
          <div
            className={cn(
              "absolute -left-20 top-16 h-72 w-72 rounded-full blur-3xl md:h-[26rem] md:w-[26rem]",
              profile.theme.orbPrimary,
            )}
          />
          <div
            className={cn(
              "absolute bottom-0 right-[-10%] h-80 w-80 rounded-full blur-3xl md:h-[30rem] md:w-[30rem]",
              profile.theme.orbSecondary,
            )}
          />
        </motion.div>
      </AnimatePresence>

      <AudioParticleField identity={identity} theme={profile.theme} />

      <div className="relative z-10 mx-auto flex min-h-screen w-full max-w-6xl flex-col px-4 py-8 sm:px-6 lg:px-8">
        <IdentityToggle
          identity={identity}
          pendingIdentity={pendingIdentity}
          onChange={handleIdentityChange}
        />

        <AnimatePresence mode="wait">
          <motion.section
            key={identity}
            initial={reduceMotion ? { opacity: 0 } : { opacity: 0, scale: 0.985 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={reduceMotion ? { opacity: 0 } : { opacity: 0, scale: 1.015 }}
            transition={sectionTransition}
            className="mx-auto mt-10 w-full max-w-5xl space-y-10 md:mt-14 md:space-y-14"
          >
            <header className="space-y-8 text-center md:space-y-10">
              <motion.div
                initial={reduceMotion ? { opacity: 0 } : { opacity: 0, y: 18 }}
                animate={{ opacity: 1, y: 0 }}
                transition={sectionTransition}
                className="mx-auto flex flex-col items-center"
              >
                {/* Avatar display comes from profile-site-data.ts. */}
                <div className="relative">
                  <div
                    className={cn(
                      "absolute inset-0 rounded-full bg-white/20 blur-3xl",
                      profile.theme.glow,
                    )}
                  />
                  <div className="absolute -inset-4 rounded-full bg-[radial-gradient(circle,rgba(255,255,255,0.28),transparent_70%)] blur-2xl" />
                  {/* Avatar size and crop live here: change h/w classes to resize, and change scale/object-* below to tweak cropping. */}
                  <div className="relative flex h-40 w-40 items-center justify-center overflow-hidden rounded-full border-4 border-white/90 bg-white/10 backdrop-blur-2xl sm:h-48 sm:w-48 md:h-56 md:w-56">
                    <Image
                      src={profile.avatar.image}
                      alt={profile.avatar.alt}
                      priority
                      sizes="(min-width: 768px) 224px, 192px"
                      className="h-full w-full scale-100 object-cover"
                    />
                  </div>
                </div>
              </motion.div>

              <motion.div
                initial={reduceMotion ? { opacity: 0 } : { opacity: 0, y: 14 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ ...sectionTransition, delay: reduceMotion ? 0 : 0.06 }}
                className="space-y-5"
              >
                {/* Name / title / bio content comes from profile-site-data.ts. */}
                <div className="space-y-3">
                  {profile.name ? (
                    <h1 className="font-serif text-5xl tracking-tight text-white sm:text-6xl md:text-7xl">
                      {profile.name}
                    </h1>
                  ) : null}
                  <p className={cn("text-sm uppercase tracking-[0.24em] sm:text-base", profile.theme.accentText)}>
                    {profile.title}
                  </p>
                </div>

                {/* Wordmark image comes from profile-site-data.ts. */}
                {/* Wordmark size lives here: change max-w / max-h classes to scale the logo image. */}
                <div className="mx-auto flex w-full max-w-sm items-center justify-center">
                  <Image
                    src={profile.wordmark.image}
                    alt={profile.wordmark.alt}
                    sizes="(min-width: 640px) 320px, 220px"
                    className="h-auto max-h-35 w-auto object-contain sm:max-h-45"
                  />
                </div>

              </motion.div>

              {"bio" in profile && profile.bio ? (
                <motion.div
                  initial={reduceMotion ? { opacity: 0 } : { opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ ...sectionTransition, delay: reduceMotion ? 0 : 0.1 }}
                  className="mx-auto max-w-3xl rounded-[32px] border border-white/20 bg-white/8 px-6 py-6 backdrop-blur-2xl sm:px-8 sm:py-7"
                >
                  <p className="text-sm leading-8 text-white/78 sm:text-base">
                    {profile.bio}
                  </p>
                </motion.div>
              ) : null}
            </header>
            <section className="mx-auto w-full max-w-[40rem] rounded-[30px] border border-white/20 bg-white/8 p-4 backdrop-blur-2xl sm:p-5 md:p-6">
              <SectionTabs
                sections={profile.sections}
                activeTab={activeTab}
                onChange={handleTabChange}
                accentClass={profile.theme.accentSurface}
                identity={identity}
              />

              {/* Works / Commission / Contact content comes from profile-site-data.ts. */}
              {/* Panel width lives on this section: change max-w-[40rem] above to scale the whole lower content area. */}
              <div className="mt-8 md:mt-10">
                <AnimatePresence mode="wait" initial={false}>
                  {activeTab === "contact" ? (
                    <motion.div
                      key={`${identity}-contact`}
                      initial={reduceMotion ? { opacity: 0 } : { opacity: 0, y: 14 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={reduceMotion ? { opacity: 0 } : { opacity: 0, y: -10 }}
                      transition={sectionTransition}
                    >
                      <ContactPanel profile={profile} />
                    </motion.div>
                  ) : (
                    <motion.div
                      key={`${identity}-${activeTab}`}
                      initial={reduceMotion ? { opacity: 0 } : { opacity: 0, y: 14 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={reduceMotion ? { opacity: 0 } : { opacity: 0, y: -10 }}
                      transition={sectionTransition}
                    >
                      <GalleryPanel
                        section={profile.sections[activeTab]}
                        currentIndex={currentGalleryIndex}
                        onPrevious={() => updateSlide(activeTab, -1)}
                        onNext={() => updateSlide(activeTab, 1)}
                        onSelect={(index) => jumpToSlide(activeTab, index)}
                        onOpenLightbox={() => setLightboxOpen(true)}
                        reduceMotion={reduceMotion}
                        accentBorder={profile.theme.accentBorder}
                        accentText={profile.theme.accentText}
                        imageTransition={imageTransition}
                      />
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            </section>
          </motion.section>
        </AnimatePresence>
      </div>

      <Lightbox
        open={lightboxOpen}
        item={currentItem}
        items={currentSection?.items ?? []}
        activeIndex={currentGalleryIndex}
        onClose={() => setLightboxOpen(false)}
        onPrevious={
          activeTab === "contact" ? undefined : () => updateSlide(activeTab, -1)
        }
        onNext={
          activeTab === "contact" ? undefined : () => updateSlide(activeTab, 1)
        }
        onSelect={(index) => {
          if (activeTab !== "contact") {
            jumpToSlide(activeTab, index);
          }
        }}
        reduceMotion={reduceMotion}
      />
    </div>
  );
}

function IdentityToggle({
  identity,
  pendingIdentity,
  onChange,
}: {
  identity: IdentityKey;
  pendingIdentity: IdentityKey | null;
  onChange: (identity: IdentityKey) => void;
}) {
  const labels = {
    personal: "卡蚯蚓",
    group: "蚯蚓麵包屋",
  } as const;

  return (
    <LayoutGroup id="identity-toggle">
      <div className="mx-auto inline-flex items-center rounded-full border border-white/15 bg-white/8 p-1.5 backdrop-blur-2xl">
        {(["personal", "group"] as const).map((value) => {
          const isActive = identity === value;
          const isPending = pendingIdentity === value;

          return (
            <button
              key={value}
              type="button"
              onClick={() => onChange(value)}
              className={cn(
                "relative min-w-28 px-5 py-2.5 text-sm uppercase tracking-[0.24em] text-white/72 transition-colors hover:text-white",
                isPending && "cursor-progress text-white/88",
              )}
            >
              {isActive && (
                <motion.span
                  layoutId="identity-pill"
                  className="absolute inset-0 rounded-full border border-white/20 bg-white/15"
                  transition={{ type: "spring", stiffness: 360, damping: 30 }}
                />
              )}
              <span className={cn("relative z-10", isActive && "text-white")}>
                {labels[value]}
              </span>
            </button>
          );
        })}
      </div>
    </LayoutGroup>
  );
}

function SectionTabs({
  sections,
  activeTab,
  onChange,
  accentClass,
  identity,
}: {
  sections: ProfileEntry["sections"];
  activeTab: TabKey;
  onChange: (tab: TabKey) => void;
  accentClass: string;
  identity: IdentityKey;
}) {
  const visibleTabs = identity === "group" ? GROUP_TABS : PERSONAL_TABS;

  return (
    <LayoutGroup id="content-tabs">
      <div className="flex flex-wrap items-center justify-center gap-5 border-b border-white/10 pb-3 sm:gap-8">
        {visibleTabs.map((tab) => {
          const isActive = activeTab === tab;

          return (
            <button
              key={tab}
              type="button"
              onClick={() => onChange(tab)}
              className="relative pb-3 text-sm uppercase tracking-[0.28em] text-white/55 transition-colors hover:text-white"
            >
              <span className={cn(isActive && "text-white")}>
                {sections[tab].label}
              </span>
              {isActive && (
                <motion.span
                  layoutId="content-tab-underline"
                  className={cn("absolute inset-x-0 bottom-0 h-px", accentClass)}
                  transition={{ type: "spring", stiffness: 420, damping: 34 }}
                />
              )}
            </button>
          );
        })}
      </div>
    </LayoutGroup>
  );
}

function GalleryPanel({
  section,
  currentIndex,
  onPrevious,
  onNext,
  onSelect,
  onOpenLightbox,
  reduceMotion,
  accentBorder,
  accentText,
  imageTransition,
}: {
  section: GallerySection;
  currentIndex: number;
  onPrevious: () => void;
  onNext: () => void;
  onSelect: (index: number) => void;
  onOpenLightbox: () => void;
  reduceMotion: boolean;
  accentBorder: string;
  accentText: string;
  imageTransition: MotionTransition;
}) {
  const item = section.items[currentIndex];

  return (
    <div className="space-y-7 md:space-y-9">
      <div className="flex flex-col gap-6 md:flex-row md:items-end md:justify-between">
        <div className="max-w-2xl space-y-3">
          <p className="text-xs uppercase tracking-[0.32em] text-white/45">
            {section.eyebrow}
          </p>
          <h2 className="font-serif text-3xl tracking-tight text-white sm:text-4xl md:text-[2.9rem]">
            {section.heading}
          </h2>
          <p           className="text-sm leading-8 text-white/68 sm:text-base [&_a]:pointer-events-auto [&_a]:underline [&_a]:underline-offset-4 [&_a]:text-white/90 hover:[&_a]:text-white" dangerouslySetInnerHTML={{ __html: section.description }} />
        </div>

        <div className="hidden items-center gap-2">
          <IconButton label="Previous image" onClick={onPrevious}>
            <ChevronLeft className="size-4" />
          </IconButton>
          <IconButton label="Next image" onClick={onNext}>
            <ChevronRight className="size-4" />
          </IconButton>
        </div>
      </div>

      <div className="overflow-hidden rounded-[26px] border border-white/20 bg-white/6 p-2.5 backdrop-blur-2xl">
        <div className="grid grid-cols-1 gap-3">
          <motion.button
            type="button"
            onClick={onOpenLightbox}
            whileHover={reduceMotion ? undefined : { scale: 1.01 }}
            whileTap={reduceMotion ? undefined : { scale: 0.995 }}
            className="group relative overflow-hidden rounded-[22px] border border-white/10 bg-black/30 text-left"
          >
            <div className="relative w-full">
              <AnimatePresence mode="wait" initial={false}>
                <motion.div
                  key={item.id}
                  initial={reduceMotion ? { opacity: 0 } : { opacity: 0, scale: 0.98 }}
                  animate={{ opacity: 1, scale: 1 }}
                  exit={reduceMotion ? { opacity: 0 } : { opacity: 0, scale: 1.02 }}
                  transition={imageTransition}
                  className="relative w-full"
                >
                  <Image
                    src={item.image}
                    alt={item.alt}
                    width={item.image.width}
                    height={item.image.height}
                    priority
                    className={cn(
                      "h-auto w-full",
                      item.fit === "contain"
                        ? "object-contain p-3 sm:p-4 md:p-5"
                        : "object-cover",
                    )}
                  />
                  <div className="pointer-events-none absolute inset-0 bg-gradient-to-t from-black/45 via-black/5 to-white/5" />
                </motion.div>
              </AnimatePresence>
            </div>

            <div className="absolute bottom-3 right-3 rounded-full border border-white/20 bg-black/35 px-2.5 py-1.5 text-[0.62rem] uppercase tracking-[0.22em] text-white/80 backdrop-blur-xl">
              Open Lightbox
            </div>
          </motion.button>
        </div>

        {item.description ? (
          <div className="px-2 pb-1 pt-2">
            <p
              className="text-sm leading-7 text-white/72 sm:text-base [&_a]:pointer-events-auto [&_a]:underline [&_a]:underline-offset-4 [&_a]:text-white/90 hover:[&_a]:text-white"
              dangerouslySetInnerHTML={{ __html: item.description }}
            />
          </div>
        ) : null}

        <div className="mt-6 flex items-center justify-center gap-3">
          <IconButton label="Previous image" onClick={onPrevious}>
            <ChevronLeft className="size-4" />
          </IconButton>

          {section.items.map((slide, index) => {
            const isActive = currentIndex === index;

            return (
              <button
                key={slide.id}
                type="button"
                onClick={() => onSelect(index)}
                className="group p-1"
                aria-label={`Go to image ${index + 1}`}
              >
                <motion.span
                  animate={{
                    width: isActive ? 24 : 8,
                    opacity: isActive ? 1 : 0.45,
                  }}
                  transition={imageTransition}
                  className={cn(
                    "block h-2 rounded-full bg-white",
                    isActive && "bg-white",
                  )}
                />
              </button>
            );
          })}

          <IconButton label="Next image" onClick={onNext}>
            <ChevronRight className="size-4" />
          </IconButton>
        </div>
      </div>
    </div>
  );
}

function ContactPanel({ profile }: { profile: ProfileEntry }) {
  return (
    <div className="grid gap-5 lg:grid-cols-[minmax(0,1fr)_minmax(0,0.9fr)]">
      <div className="rounded-[28px] border border-white/20 bg-white/6 p-6 backdrop-blur-2xl sm:p-7">
        <p className="text-xs uppercase tracking-[0.32em] text-white/45">
          {profile.sections.contact.eyebrow}
        </p>
        <h2 className="mt-3 font-serif text-3xl tracking-tight text-white sm:text-4xl">
          {profile.sections.contact.heading}
        </h2>
        <p className="mt-4 text-sm leading-8 text-white/70 sm:text-base">
          {profile.sections.contact.description}
        </p>
      </div>

      <div className="space-y-4">
        {profile.sections.contact.links.map((link, index) => {
          const Icon = SOCIAL_ICONS[link.icon];

          return (
            <motion.a
              key={link.id}
              href={link.href}
              target="_blank"
              rel="noopener noreferrer"
              initial={{ opacity: 0, y: 16 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.4, ease: LUXE_EASE, delay: index * 0.05 }}
              whileHover={{ y: -2 }}
              className="group flex items-center gap-4 rounded-[24px] border border-white/20 bg-white/8 px-5 py-4 backdrop-blur-2xl"
            >
              <div className="flex size-12 items-center justify-center rounded-full border border-white/12 bg-black/25">
                <Icon className="size-5 text-white" />
              </div>

              <div className="min-w-0 flex-1">
                <p className="text-xs uppercase tracking-[0.28em] text-white/45">
                  {link.label}
                </p>
                <p className="mt-1 truncate text-sm text-white/85 sm:text-base">
                  {link.value}
                </p>
              </div>

              <ArrowUpRight className="size-4 text-white/50 transition-transform duration-300 group-hover:-translate-y-0.5 group-hover:translate-x-0.5 group-hover:text-white" />
            </motion.a>
          );
        })}
      </div>
    </div>
  );
}

function Lightbox({
  open,
  item,
  items,
  activeIndex,
  onClose,
  onPrevious,
  onNext,
  onSelect,
  reduceMotion,
}: {
  open: boolean;
  item: GalleryItem | null;
  items: GalleryItem[];
  activeIndex: number;
  onClose: () => void;
  onPrevious?: () => void;
  onNext?: () => void;
  onSelect: (index: number) => void;
  reduceMotion: boolean;
}) {
  if (!item) {
    return null;
  }

  const transition: MotionTransition = {
    duration: reduceMotion ? 0.18 : 0.4,
    ease: reduceMotion ? QUICK_EASE : LUXE_EASE,
  };

  return (
    <AnimatePresence>
      {open ? (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          transition={transition}
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 px-4 py-6 backdrop-blur-xl sm:px-6"
          onClick={onClose}
        >
          <motion.div
            initial={reduceMotion ? { opacity: 0 } : { opacity: 0, scale: 0.985 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={reduceMotion ? { opacity: 0 } : { opacity: 0, scale: 1.01 }}
            transition={transition}
            onClick={(event) => event.stopPropagation()}
            role="dialog"
            aria-modal="true"
            aria-label={item.title}
            className="w-full max-w-6xl"
          >
            <div className="mb-4 flex items-center justify-between gap-4 text-white/80">
              <div>
                <p className="text-xs uppercase tracking-[0.28em] text-white/45">
                  Expanded View
                </p>
                <h3 className="mt-2 font-serif text-2xl tracking-tight text-white sm:text-3xl">
                  {item.title}
                </h3>
              </div>

              <IconButton label="Close lightbox" onClick={onClose}>
                <X className="size-4" />
              </IconButton>
            </div>

            <div className="overflow-hidden rounded-[32px] border border-white/10 bg-white/6 p-3 backdrop-blur-2xl">
              <div className="relative overflow-hidden rounded-[28px] bg-black/35">
                {/* Lightbox image size lives here: keep this close to 16:9 when your source artwork is wide. */}
                <div className="relative aspect-[16/9] min-h-[18rem] sm:min-h-[26rem]">
                  <AnimatePresence mode="wait" initial={false}>
                    <motion.div
                      key={item.id}
                      initial={reduceMotion ? { opacity: 0 } : { opacity: 0, scale: 0.985 }}
                      animate={{ opacity: 1, scale: 1 }}
                      exit={reduceMotion ? { opacity: 0 } : { opacity: 0, scale: 1.015 }}
                      transition={transition}
                      className="absolute inset-0"
                    >
                      <Image
                        src={item.image}
                        alt={item.alt}
                        fill
                        sizes="100vw"
                        className={cn(
                          item.fit === "contain"
                            ? "object-contain p-4 sm:p-6"
                            : "object-cover",
                        )}
                      />
                      <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(circle_at_top,rgba(255,255,255,0.14),transparent_55%)]" />
                    </motion.div>
                  </AnimatePresence>
                </div>

                <div className="absolute inset-y-0 left-3 flex items-center">
                  <IconButton label="Previous image" onClick={onPrevious}>
                    <ChevronLeft className="size-4" />
                  </IconButton>
                </div>

                <div className="absolute inset-y-0 right-3 flex items-center">
                  <IconButton label="Next image" onClick={onNext}>
                    <ChevronRight className="size-4" />
                  </IconButton>
                </div>
              </div>

              <div className="mt-5 flex flex-col gap-4 sm:flex-row sm:items-end sm:justify-between">
                <p className="max-w-2xl text-sm leading-7 text-white/72 sm:text-base [&_a]:pointer-events-auto [&_a]:underline [&_a]:underline-offset-4 [&_a]:text-white/90 hover:[&_a]:text-white" dangerouslySetInnerHTML={{ __html: item.description }} />

                <div className="flex items-center justify-center gap-2">
                  {items.map((slide, index) => {
                    const isActive = activeIndex === index;

                    return (
                      <button
                        key={slide.id}
                        type="button"
                        onClick={() => onSelect(index)}
                        className="group p-1"
                        aria-label={`Show image ${index + 1}`}
                      >
                        <motion.span
                          animate={{
                            width: isActive ? 24 : 8,
                            opacity: isActive ? 1 : 0.45,
                          }}
                          transition={transition}
                          className="block h-2 rounded-full bg-white"
                        />
                      </button>
                    );
                  })}
                </div>
              </div>
            </div>
          </motion.div>
        </motion.div>
      ) : null}
    </AnimatePresence>
  );
}

function IconButton({
  label,
  onClick,
  children,
}: {
  label: string;
  onClick?: () => void;
  children: ReactNode;
}) {
  return (
    <motion.button
      type="button"
      aria-label={label}
      onClick={(event) => {
        event.stopPropagation();
        onClick?.();
      }}
      whileHover={{ y: -1 }}
      whileTap={{ scale: 0.96 }}
      className="flex size-10 items-center justify-center rounded-full border border-white/15 bg-white/8 text-white backdrop-blur-2xl transition-colors hover:bg-white/14"
    >
      {children}
    </motion.button>
  );
}

function wrapIndex(index: number, total: number) {
  if (total === 0) {
    return 0;
  }

  return (index + total) % total;
}

function preloadProfileAssets(profile: ProfileEntry) {
  return Promise.all(
    getCoreAssets(profile).map((asset) => preloadImageAsset(asset)),
  ).then(() => undefined);
}

function getCoreAssets(profile: ProfileEntry) {
  return [
    profile.avatar.image,
    profile.wordmark.image,
    profile.sections.works.items[0]?.image,
    profile.sections.commission.items[0]?.image,
  ].filter((asset): asset is StaticImageData => Boolean(asset));
}

function preloadImageAsset(asset: StaticImageData) {
  const cached = PRELOADED_ASSETS.get(asset.src);
  if (cached) {
    return cached;
  }

  const promise = new Promise<void>((resolve) => {
    if (typeof window === "undefined") {
      resolve();
      return;
    }

    const image = new window.Image();
    let settled = false;

    const finalize = () => {
      if (settled) {
        return;
      }

      settled = true;
      resolve();
    };

    const decodeImage = () => {
      if (typeof image.decode === "function") {
        image.decode().catch(() => undefined).finally(finalize);
        return;
      }

      finalize();
    };

    image.decoding = "async";
    image.onload = decodeImage;
    image.onerror = finalize;
    image.src = asset.src;

    if (image.complete) {
      decodeImage();
    }
  });

  PRELOADED_ASSETS.set(asset.src, promise);
  return promise;
}

type SiteDataMap = Record<keyof ProfileContentMap, ProfileEntry>;
type BezierEase = [number, number, number, number];
type MotionTransition = {
  duration: number;
  ease: BezierEase;
};

type ProfileEntry = ProfileContentEntry & {
  theme: AudioParticleTheme & {
    background: string;
    backgroundImageOpacity: string;
    orbPrimary: string;
    orbSecondary: string;
    accentText: string;
    accentSurface: string;
    accentBorder: string;
    badge: string;
    glow: string;
  };
};
type IdentityKey = keyof ProfileContentMap;
type GalleryTab = (typeof GALLERY_TABS)[number];
type TabKey = (typeof TAB_ORDER)[number];
type SlideState = Record<IdentityKey, Record<GalleryTab, number>>;
